import{bV as n,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const _=JSON.parse('{"title":"单个角色生成","description":"","frontmatter":{},"headers":[],"relativePath":"mumuainovel/单个角色生成.md","filePath":"mumuainovel/单个角色生成.md","lastUpdated":1777768003000}'),t={name:"mumuainovel/单个角色生成.md"};function e(i,s,o,c,u,q){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="单个角色生成" tabindex="-1">单个角色生成 <a class="header-anchor" href="#单个角色生成" aria-label="Permalink to &quot;单个角色生成&quot;">​</a></h1><blockquote><p>模板键: <code>SINGLE_CHARACTER_GENERATION</code> 分类: 角色生成 描述: 生成单个角色的详细设定 参数: [&quot;project_context&quot;, &quot;user_input&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是专业的角色设定师，擅长创建能够驱动剧情发展的立体人物，而不是静态设定。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task&gt;</span></span>
<span class="line"><span>【设计任务】</span></span>
<span class="line"><span>根据用户需求和项目上下文，创建一个&quot;可写性强&quot;的角色：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要求角色必须：</span></span>
<span class="line"><span>- 能推动剧情发展</span></span>
<span class="line"><span>- 能通过行为和对话体现性格</span></span>
<span class="line"><span>- 具备内在冲突和行动逻辑</span></span>
<span class="line"><span>- 不是设定说明，而是&quot;能被写出来的人&quot;</span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;context priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【项目上下文】</span></span>
<span class="line"><span>{project_context}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【用户需求】</span></span>
<span class="line"><span>{user_input}</span></span>
<span class="line"><span>&lt;/context&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【输出格式】</span></span>
<span class="line"><span>生成完整的角色卡片JSON对象：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;name&quot;: &quot;角色姓名（如用户未提供则生成符合世界观的名字）&quot;,</span></span>
<span class="line"><span>  &quot;age&quot;: &quot;年龄（具体数字或年龄段）&quot;,</span></span>
<span class="line"><span>  &quot;gender&quot;: &quot;男/女/其他&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;appearance&quot;: &quot;外貌描述：必须包含可被剧情使用的特征，例如伤疤、习惯性动作、标志性穿着等（100-150字）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;personality&quot;: &quot;性格结构：1.表面性格（他人看到的）2.真实内在（隐藏面）3.明显缺陷（必须影响行为）4.一个具体行为体现（例如说话方式或习惯）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;behavior_rules&quot;: &quot;行为规则：描述角色在不同情境下的行动逻辑，例如面对冲突的反应、面对情感的态度、决策方式等（必须可直接用于写剧情，100-150字）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;core_conflict&quot;: &quot;核心矛盾：角色内心最核心的冲突或执念，必须能反复推动剧情（80-120字）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;background&quot;: &quot;背景故事：必须包含1.一个关键过去事件（塑造性格）2.一个未解决的问题（影响现在）3.该问题如何影响主线剧情（200-300字）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;motivation&quot;: &quot;当前动机：角色此阶段最想达成的目标（必须具体）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;fears&quot;: &quot;核心恐惧：角色最害怕发生的事情（必须影响选择）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;story_hooks&quot;: [</span></span>
<span class="line"><span>    &quot;可用于剧情发展的事件或冲突点1&quot;,</span></span>
<span class="line"><span>    &quot;可用于剧情发展的事件或冲突点2&quot;,</span></span>
<span class="line"><span>    &quot;可用于剧情发展的事件或冲突点3&quot;</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;traits&quot;: [&quot;能力或特长1&quot;, &quot;能力或特长2&quot;, &quot;能力或特长3&quot;],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;relationships_text&quot;: &quot;用自然语言描述主要人际关系和潜在冲突&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;relationships&quot;: [</span></span>
<span class="line"><span>    {{</span></span>
<span class="line"><span>      &quot;target_character_name&quot;: &quot;已存在角色&quot;,</span></span>
<span class="line"><span>      &quot;relationship_type&quot;: &quot;关系类型&quot;,</span></span>
<span class="line"><span>      &quot;intimacy_level&quot;: 50,</span></span>
<span class="line"><span>      &quot;description&quot;: &quot;关系中的矛盾或依赖&quot;,</span></span>
<span class="line"><span>      &quot;started_at&quot;: &quot;关系开始的故事时间点（可选）&quot;</span></span>
<span class="line"><span>    }}</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;organization_memberships&quot;: [</span></span>
<span class="line"><span>    {{</span></span>
<span class="line"><span>      &quot;organization_name&quot;: &quot;已存在的组织名称&quot;,</span></span>
<span class="line"><span>      &quot;position&quot;: &quot;职位&quot;,</span></span>
<span class="line"><span>      &quot;rank&quot;: 5,</span></span>
<span class="line"><span>      &quot;loyalty&quot;: 70,</span></span>
<span class="line"><span>      &quot;joined_at&quot;: &quot;加入时间（可选）&quot;,</span></span>
<span class="line"><span>      &quot;status&quot;: &quot;active&quot;</span></span>
<span class="line"><span>    }}</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  &quot;career_info&quot;: {{</span></span>
<span class="line"><span>    &quot;main_career_name&quot;: &quot;从可用主职业列表中选择的职业名称&quot;,</span></span>
<span class="line"><span>    &quot;main_career_stage&quot;: 5,</span></span>
<span class="line"><span>    &quot;sub_careers&quot;: [</span></span>
<span class="line"><span>      {{</span></span>
<span class="line"><span>        &quot;career_name&quot;: &quot;从可用副职业列表中选择的职业名称&quot;,</span></span>
<span class="line"><span>        &quot;stage&quot;: 3</span></span>
<span class="line"><span>      }}</span></span>
<span class="line"><span>    ]</span></span>
<span class="line"><span>  }}</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span>&lt;/output&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【职业信息说明】</span></span>
<span class="line"><span>如果项目上下文包含职业列表：</span></span>
<span class="line"><span>- 主职业：从可用主职业列表中选择最符合角色的职业</span></span>
<span class="line"><span>- 主职业阶段：根据角色实力设定合理阶段（1到max_stage）</span></span>
<span class="line"><span>- 副职业：可选择0-2个副职业</span></span>
<span class="line"><span>- ⚠️ 填写职业名称而非ID，系统会自动匹配</span></span>
<span class="line"><span>- 职业选择必须与角色背景、能力和定位高度契合</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【关系类型参考】</span></span>
<span class="line"><span>- 家族：父亲、母亲、兄弟、姐妹、子女、配偶、恋人</span></span>
<span class="line"><span>- 社交：师父、徒弟、朋友、同学、同事、邻居、知己</span></span>
<span class="line"><span>- 职业：上司、下属、合作伙伴</span></span>
<span class="line"><span>- 敌对：敌人、仇人、竞争对手、宿敌</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【数值范围】</span></span>
<span class="line"><span>- intimacy_level：-100到100（负值表示敌对）</span></span>
<span class="line"><span>- loyalty：0到100</span></span>
<span class="line"><span>- rank：0到10</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【核心约束】</span></span>
<span class="line"><span>❗所有设定必须能够在剧情中被表现出来，禁止纯描述</span></span>
<span class="line"><span>❗角色必须具备主动做决定并影响剧情的能力</span></span>
<span class="line"><span>❗至少包含一个会导致剧情冲突的性格缺陷</span></span>
<span class="line"><span>❗角色行为必须符合其行为规则，不可随剧情随意变化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【角色质量要求】</span></span>
<span class="line"><span>✅ 不脸谱化（必须有矛盾）</span></span>
<span class="line"><span>✅ 有缺陷（必须影响剧情）</span></span>
<span class="line"><span>✅ 有动机（必须驱动行动）</span></span>
<span class="line"><span>✅ 有恐惧（必须影响选择）</span></span>
<span class="line"><span>✅ 主角：有成长空间和目标动机</span></span>
<span class="line"><span>✅ 反派：有合理动机，不脸谱化</span></span>
<span class="line"><span>✅ 配角：有独特性，不是工具人</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【剧情驱动要求】</span></span>
<span class="line"><span>❗角色必须能够制造冲突、做出选择、改变局势</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【关系约束】</span></span>
<span class="line"><span>✅ relationships只引用已存在角色</span></span>
<span class="line"><span>✅ organization_memberships只引用已存在组织</span></span>
<span class="line"><span>✅ 无则为空数组</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【格式约束】</span></span>
<span class="line"><span>✅ 纯JSON输出</span></span>
<span class="line"><span>❌ 禁止markdown</span></span>
<span class="line"><span>❌ 禁止特殊符号（引号、括号等出现在描述中）</span></span>
<span class="line"><span>❌ 禁止引用不存在实体</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span></code></pre></div>`,3)])])}const m=n(t,[["render",e]]);export{_ as __pageData,m as default};
